import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Box, Backdrop } from '@mui/material';
import FAWDrawer from '../../FAWDrawer';
import FAWInput from '../../FAWInput';
import FAWButton from '../../FAWButton';
import FAWTypography from '../../FAWTypography';
import FAWLoader from '../../FAWLoader';
import { showToast } from '../../shared/ToastManager';
import { colors } from '../../../../utils/designTokens';
import { CheckCircle, Error as ErrorIcon } from '@mui/icons-material';

const WorkflowDefCloneDrawer = ({ 
  open = false, 
  onClose, 
  workflowDefId,
  workflowName = '',
  isSnippet = false,
  onSuccess
}) => {
  const [name, setName] = useState(`Copy of ${workflowName}`);
  const [isValidating, setIsValidating] = useState(false);
  const [validationState, setValidationState] = useState(null); // 'valid', 'invalid', 'empty', null
  const [errorMessage, setErrorMessage] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const validationTimeoutRef = useRef(null);

  // Reset state when drawer opens/closes or workflow changes
  useEffect(() => {
    if (open) {
      const initialName = `Copy of ${workflowName}`;
      setName(initialName);
      setValidationState(null);
      setErrorMessage('');
      // Trigger validation for initial name
      validateName(initialName);
    }
  }, [open, workflowName, validateName]);

  // Validate name with debouncing
  const validateName = useCallback(async (value) => {
    // Clear existing timeout
    if (validationTimeoutRef.current) {
      clearTimeout(validationTimeoutRef.current);
    }

    const trimmedValue = value?.trim() || '';

    // Empty validation
    if (!trimmedValue || trimmedValue.length === 0) {
      setValidationState('empty');
      setErrorMessage('Name cannot be empty.');
      return false;
    }

    // Debounce the API call
    validationTimeoutRef.current = setTimeout(async () => {
      setIsValidating(true);
      try {
        const controllerName = isSnippet ? '/WorkflowTaskDefSnippet' : '/WorkflowDef';
        const response = await fetch(`${controllerName}/CheckName?name=${encodeURIComponent(trimmedValue)}`, {
          method: 'GET',
          headers: {
            'Accept': 'application/json'
          },
          credentials: 'include'
        });

        if (response.ok) {
          const data = await response.json();
          if (data.isValid) {
            setValidationState('valid');
            setErrorMessage('');
          } else {
            setValidationState('invalid');
            setErrorMessage(data.message || `Name [${trimmedValue}] has been used.`);
          }
        } else {
          setValidationState('invalid');
          setErrorMessage('Error validating name. Please try again.');
        }
      } catch (error) {
        console.error('Error validating name:', error);
        setValidationState('invalid');
        setErrorMessage('Error validating name. Please try again.');
        showToast.error('Error validating name. Please try again.', 3000);
      } finally {
        setIsValidating(false);
      }
    }, 500); // 500ms debounce
  }, [isSnippet]);

  // Handle name change
  const handleNameChange = useCallback((e) => {
    const newValue = e?.target?.value ?? e?.value ?? e ?? '';
    setName(newValue);
    validateName(newValue);
  }, [validateName]);

  // Handle form submission
  const handleSubmit = useCallback(async (e) => {
    e?.preventDefault?.();

    const trimmedName = name?.trim() || '';
    
    // Final validation before submit
    if (!trimmedName || trimmedName.length === 0) {
      setValidationState('empty');
      setErrorMessage('Name cannot be empty.');
      return;
    }

    // Check if validation passed
    if (validationState !== 'valid') {
      // Trigger validation if not done yet
      await validateName(trimmedName);
      return;
    }

    setIsSubmitting(true);
    
    try {
      const controllerName = isSnippet ? 'WorkflowTaskDefSnippet' : 'WorkflowDef';
      
      // Create form data
      const formData = new FormData();
      formData.append('Id', workflowDefId);
      formData.append('Name', trimmedName);
      if (isSnippet) {
        formData.append('IsSnippet', 'True');
      }

      // Get anti-forgery token
      const token = document.querySelector('input[name="__RequestVerificationToken"]')?.value || '';
      if (token) {
        formData.append('__RequestVerificationToken', token);
      }

      const response = await fetch(`/${controllerName}/SaveClone`, {
        method: 'POST',
        body: formData,
        credentials: 'include'
      });

      if (response.ok) {
        // Success - show toast and close drawer
        const entityType = isSnippet ? 'workflow snippet' : 'workflow';
        const toastMessage = `${entityType.charAt(0).toUpperCase() + entityType.slice(1)} cloned successfully`;
        const toastDuration = 30000;
        
        // Use Atlas toast if available (for snippet/workflow pages), otherwise use ToastManager
        if (typeof window !== 'undefined' && typeof window.showAtlasToast === 'function') {
          window.showAtlasToast(toastMessage, 'success', toastDuration);
        } else if (typeof window !== 'undefined' && window.mountReactComponentIfExists) {
          // Fallback: use mountReactComponentIfExists directly
          const toastContainer = document.getElementById('atlas-toast-container') || (() => {
            const container = document.createElement('div');
            container.id = 'atlas-toast-container';
            document.body.appendChild(container);
            return container;
          })();
          
          window.mountReactComponentIfExists('toast', 'atlas-toast-container', {
            message: toastMessage,
            type: 'success',
            duration: toastDuration,
            position: 'top-right',
            open: true
          });
        } else {
          // Fallback to ToastManager
          showToast.success(toastMessage, toastDuration);
        }
        
        if (onSuccess) {
          onSuccess();
        }
        handleClose();
        
        // Delay reload to allow toast to be seen - wait for toast duration plus a small buffer
        setTimeout(() => {
          window.location.reload();
        },  2000);
      } else {
        const errorText = await response.text();
        const errorMsg = 'Failed to clone workflow. Please try again.';
        setErrorMessage(errorMsg);
        showToast.error(errorMsg, 5000);
        console.error('Clone failed:', errorText);
      }
    } catch (error) {
      console.error('Error cloning workflow:', error);
      const errorMsg = 'Error cloning workflow. Please try again.';
      setErrorMessage(errorMsg);
      showToast.error(errorMsg, 5000);
    } finally {
      setIsSubmitting(false);
    }
  }, [name, validationState, workflowDefId, isSnippet, onSuccess, validateName]);

  const handleClose = useCallback(() => {
    setName(`Copy of ${workflowName}`);
    setValidationState(null);
    setErrorMessage('');
    setIsSubmitting(false);
    if (validationTimeoutRef.current) {
      clearTimeout(validationTimeoutRef.current);
    }
    if (onClose) {
      onClose();
    }
  }, [onClose, workflowName]);

  const isSaveDisabled = isSubmitting || isValidating || validationState !== 'valid';

  const drawerActions = [
    {
      text: 'Cancel',
      variant: 'outlined',
      color: 'inherit',
      onClick: handleClose,
      disabled: isSubmitting,
      handlerType: 'custom'
    },
    {
      text: isSubmitting ? 'Cloning...' : 'OK',
      variant: 'contained',
      color: 'primary',
      onClick: handleSubmit,
      disabled: isSaveDisabled,
      handlerType: 'custom'
    }
  ];

  return (
    <>
      <FAWDrawer
        open={open}
        onClose={handleClose}
        title="Clone from existing workflow"
        width={500}
        anchor="right"
        variant="temporary"
        showCloseButton={true}
        showHeader={true}
        customFooter={true}
        actions={drawerActions}
      >
        <Box sx={{ p: 3 }}>
          <Box sx={{ mb: 3 }}>
            <FAWTypography 
              variant="body2" 
              sx={{ mb: 1, fontWeight: 500 }}
              component="label"
            >
              New workflow name
            </FAWTypography>
            
            <Box sx={{ position: 'relative' }}>
              <FAWInput
                value={name}
                onChange={handleNameChange}
                placeholder="Enter workflow name"
                fullWidth={true}
                autoFocus
                error={validationState === 'invalid' || validationState === 'empty'}
                endAdornment={
                  validationState === 'valid' && !isValidating ? (
                    <CheckCircle sx={{ color: colors.status.success, fontSize: '20px' }} />
                  ) : validationState === 'invalid' ? (
                    <ErrorIcon sx={{ color: colors.status.error, fontSize: '20px' }} />
                  ) : null
                }
                sx={{
                  '& .MuiOutlinedInput-root': {
                    backgroundColor: colors.background.default
                  }
                }}
              />
              
              {errorMessage && (
                <FAWTypography 
                  variant="caption" 
                  sx={{ 
                    color: colors.status.error, 
                    mt: 0.5, 
                    display: 'block' 
                  }}
                >
                  {errorMessage}
                </FAWTypography>
              )}
              
              {isValidating && (
                <FAWTypography 
                  variant="caption" 
                  sx={{ 
                    color: colors.type.secondary, 
                    mt: 0.5, 
                    display: 'block' 
                  }}
                >
                  Validating...
                </FAWTypography>
              )}
            </Box>
          </Box>
        </Box>
      </FAWDrawer>

      {/* Loading backdrop for submission */}
      <Backdrop
        open={isSubmitting}
        sx={{
          zIndex: (theme) => theme.zIndex.drawer + 1,
          backgroundColor: 'rgba(0, 0, 0, 0.5)',
          backdropFilter: 'blur(2px)'
        }}
      >
        <FAWLoader 
          label={isSnippet ? "Cloning workflow snippet..." : "Cloning workflow..."}
          size={40}
          inline={false}
          sx={{
            backgroundColor: 'transparent',
            borderRadius: 0,
            padding: 0,
            boxShadow: 'none',
            minWidth: 'auto',
            maxWidth: 'none',
            '& .MuiTypography-root': {
              color: 'white',
              fontWeight: 500,
              textShadow: '0 1px 2px rgba(0, 0, 0, 0.5)'
            }
          }}
        />
      </Backdrop>
    </>
  );
};

export default WorkflowDefCloneDrawer;

